import{_ as a,o,c as t,ag as r}from"./chunks/framework.BGkQCay2.js";const p=JSON.parse('{"title":"Frequently Asked Questions","description":"","frontmatter":{},"headers":[],"relativePath":"guide/faq.md","filePath":"guide/faq.md"}'),i={name:"guide/faq.md"};function s(n,e,l,c,d,h){return o(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="frequently-asked-questions" tabindex="-1">Frequently Asked Questions <a class="header-anchor" href="#frequently-asked-questions" aria-label="Permalink to &quot;Frequently Asked Questions&quot;">​</a></h1><h2 id="general" tabindex="-1">General <a class="header-anchor" href="#general" aria-label="Permalink to &quot;General&quot;">​</a></h2><h3 id="what-is-vex" tabindex="-1">What is Vex? <a class="header-anchor" href="#what-is-vex" aria-label="Permalink to &quot;What is Vex?&quot;">​</a></h3><p>Vex is a modern systems programming language that combines Rust&#39;s memory safety with Go&#39;s simplicity and Mojo&#39;s automatic SIMD/GPU acceleration. It compiles to native code via LLVM 21.</p><h3 id="is-vex-ready-for-production" tabindex="-1">Is Vex ready for production? <a class="header-anchor" href="#is-vex-ready-for-production" aria-label="Permalink to &quot;Is Vex ready for production?&quot;">​</a></h3><p>Vex is pre-1.0 (currently v0.1.2). It is suitable for side projects, tools, and experimentation. Production use is at your own risk -- the language, compiler, and standard library are still evolving.</p><h3 id="what-platforms-does-vex-support" tabindex="-1">What platforms does Vex support? <a class="header-anchor" href="#what-platforms-does-vex-support" aria-label="Permalink to &quot;What platforms does Vex support?&quot;">​</a></h3><p>macOS (ARM64 and x86_64) and Linux (x86_64 and ARM64) are production-ready. FreeBSD and Windows are in beta. WASM (browser playground) is experimental.</p><h3 id="what-license-is-vex-under" tabindex="-1">What license is Vex under? <a class="header-anchor" href="#what-license-is-vex-under" aria-label="Permalink to &quot;What license is Vex under?&quot;">​</a></h3><p>MIT. Use it freely for any purpose, commercial or otherwise.</p><h2 id="language-design" tabindex="-1">Language Design <a class="header-anchor" href="#language-design" aria-label="Permalink to &quot;Language Design&quot;">​</a></h2><h3 id="why-doesn-t-vex-use-mut-like-rust" tabindex="-1">Why doesn&#39;t Vex use <code>mut</code> like Rust? <a class="header-anchor" href="#why-doesn-t-vex-use-mut-like-rust" aria-label="Permalink to &quot;Why doesn&#39;t Vex use `mut` like Rust?&quot;">​</a></h3><p>Vex uses <code>!</code> suffix syntax (<code>let!</code>, <code>&amp;T!</code>, <code>&amp;T!</code> for mutable) instead of the <code>mut</code> keyword. This makes mutability a type-level property rather than a keyword modifier, which integrates better with generics and contracts.</p><h3 id="why-instead-of-for-method-calls" tabindex="-1">Why <code>.</code> instead of <code>::</code> for method calls? <a class="header-anchor" href="#why-instead-of-for-method-calls" aria-label="Permalink to &quot;Why `.` instead of `::` for method calls?&quot;">​</a></h3><p>Vex uses <code>.</code> for ALL member access -- methods, static functions, enum variants, namespaces. This simplifies the mental model: one operator, one meaning. <code>Some(x)</code> not <code>Option::Some(x)</code>, <code>Vec.new()</code> not <code>Vec::new()</code>.</p><h3 id="does-vex-have-a-garbage-collector" tabindex="-1">Does Vex have a garbage collector? <a class="header-anchor" href="#does-vex-have-a-garbage-collector" aria-label="Permalink to &quot;Does Vex have a garbage collector?&quot;">​</a></h3><p>No. Vex uses ownership and borrowing (like Rust) with VUMM (Vex Unified Memory Model) for automatic heap management. VUMM infers whether <code>Box&lt;T&gt;</code> should be single-owner, reference-counted, or atomically reference-counted.</p><h3 id="how-is-vex-different-from-rust" tabindex="-1">How is Vex different from Rust? <a class="header-anchor" href="#how-is-vex-different-from-rust" aria-label="Permalink to &quot;How is Vex different from Rust?&quot;">​</a></h3><p>Vex has Go-like syntax simplicity, automatic SIMD vectorization, first-class GPU support via SIR, VUMM automatic ownership inference, and a more comprehensive standard library. Rust has a massively larger ecosystem, more production validation, and the most sophisticated type system of any mainstream language.</p><h3 id="how-is-vex-different-from-go" tabindex="-1">How is Vex different from Go? <a class="header-anchor" href="#how-is-vex-different-from-go" aria-label="Permalink to &quot;How is Vex different from Go?&quot;">​</a></h3><p>Vex has no garbage collector (ownership + VUMM instead), full generics with contracts, sum types with pattern matching, automatic SIMD/GPU acceleration, and null safety via <code>Option&lt;T&gt;</code>. Go compiles faster and has a larger ecosystem.</p><h2 id="compilation" tabindex="-1">Compilation <a class="header-anchor" href="#compilation" aria-label="Permalink to &quot;Compilation&quot;">​</a></h2><h3 id="why-is-my-compile-slow" tabindex="-1">Why is my compile slow? <a class="header-anchor" href="#why-is-my-compile-slow" aria-label="Permalink to &quot;Why is my compile slow?&quot;">​</a></h3><p>Vex uses LLVM for codegen, which accounts for most compilation time. Use <code>vex check</code> for fast type-checking without codegen during development. Incremental compilation (<code>--incremental</code>) caches intermediate results. Release builds (<code>--release</code>) take longer due to optimization passes.</p><h3 id="can-i-cross-compile" tabindex="-1">Can I cross-compile? <a class="header-anchor" href="#can-i-cross-compile" aria-label="Permalink to &quot;Can I cross-compile?&quot;">​</a></h3><p>Yes. Use <code>--target</code> to specify the target triple:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">vex</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> compile</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --target</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> x86_64-unknown-linux-gnu</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> main.vx</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">      # from macOS to Linux</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">vex</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> compile</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --target</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> aarch64-apple-darwin</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> main.vx</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">           # from Intel Mac to Apple Silicon</span></span></code></pre></div><h3 id="what-s-the-difference-between-vex-run-and-vex-compile" tabindex="-1">What&#39;s the difference between <code>vex run</code> and <code>vex compile</code>? <a class="header-anchor" href="#what-s-the-difference-between-vex-run-and-vex-compile" aria-label="Permalink to &quot;What&#39;s the difference between `vex run` and `vex compile`?&quot;">​</a></h3><p><code>vex run</code> compiles to a temporary executable and runs it in one step. Best for development. <code>vex compile</code> produces a standalone binary. Best for production.</p><h2 id="memory-and-safety" tabindex="-1">Memory and Safety <a class="header-anchor" href="#memory-and-safety" aria-label="Permalink to &quot;Memory and Safety&quot;">​</a></h2><h3 id="do-i-need-to-worry-about-memory-leaks" tabindex="-1">Do I need to worry about memory leaks? <a class="header-anchor" href="#do-i-need-to-worry-about-memory-leaks" aria-label="Permalink to &quot;Do I need to worry about memory leaks?&quot;">​</a></h3><p>Vex&#39;s ownership system prevents most leaks automatically. <code>Drop</code> ensures resources are freed when they go out of scope. However, reference cycles (in <code>SharedRc</code>/<code>AtomicArc</code>) can cause leaks -- use weak references or break cycles manually.</p><h3 id="what-s-the-difference-between-box-t-ptr-t-and-raw-pointers" tabindex="-1">What&#39;s the difference between <code>Box&lt;T&gt;</code>, <code>Ptr&lt;T&gt;</code>, and raw pointers? <a class="header-anchor" href="#what-s-the-difference-between-box-t-ptr-t-and-raw-pointers" aria-label="Permalink to &quot;What&#39;s the difference between `Box&lt;T&gt;`, `Ptr&lt;T&gt;`, and raw pointers?&quot;">​</a></h3><ul><li><code>Box&lt;T&gt;</code>: Heap-allocated, automatically managed (VUMM selects strategy). Use for general heap allocation.</li><li><code>Ptr&lt;T&gt;</code>: Typed pointer wrapper with safe methods (<code>readAt</code>, <code>writeAt</code>, <code>offset</code>). Use for pointer arithmetic.</li><li><code>ptr</code> / <code>*T</code>: Raw unchecked pointers. Use only in <code>unsafe</code> blocks for FFI and low-level code.</li></ul><h3 id="what-happens-on-null-pointer-dereference" tabindex="-1">What happens on null pointer dereference? <a class="header-anchor" href="#what-happens-on-null-pointer-dereference" aria-label="Permalink to &quot;What happens on null pointer dereference?&quot;">​</a></h3><p>Vex doesn&#39;t have null pointers in safe code. <code>Option&lt;T&gt;</code> replaces null. Raw pointer dereference requires <code>unsafe</code> blocks. Out-of-bounds access on <code>Span&lt;T&gt;</code> causes a panic with a clear error message.</p><h2 id="concurrency" tabindex="-1">Concurrency <a class="header-anchor" href="#concurrency" aria-label="Permalink to &quot;Concurrency&quot;">​</a></h2><h3 id="how-many-goroutines-can-i-spawn" tabindex="-1">How many goroutines can I spawn? <a class="header-anchor" href="#how-many-goroutines-can-i-spawn" aria-label="Permalink to &quot;How many goroutines can I spawn?&quot;">​</a></h3><p>Millions. Goroutines start with an 8 KB stack that grows as needed. The M:N scheduler distributes them across available CPU cores efficiently. Memory overhead per idle goroutine is approximately 200 bytes.</p><h3 id="do-channels-cause-deadlocks" tabindex="-1">Do channels cause deadlocks? <a class="header-anchor" href="#do-channels-cause-deadlocks" aria-label="Permalink to &quot;Do channels cause deadlocks?&quot;">​</a></h3><p>They can, like in any language. Unbuffered channels (capacity 0) require simultaneous send and receive. Buffered channels block when full/empty. The runtime can detect simple deadlocks (all goroutines blocked).</p><h3 id="how-do-i-share-data-between-goroutines" tabindex="-1">How do I share data between goroutines? <a class="header-anchor" href="#how-do-i-share-data-between-goroutines" aria-label="Permalink to &quot;How do I share data between goroutines?&quot;">​</a></h3><p>Use <code>Channel&lt;T&gt;</code> for message passing (&quot;don&#39;t communicate by sharing memory, share memory by communicating&quot;). For shared state, use <code>Mutex&lt;T&gt;</code>, <code>RwLock&lt;T&gt;</code>, or atomics. VUMM automatically upgrades <code>Box&lt;T&gt;</code> to <code>AtomicArc</code> when shared across goroutines.</p><h2 id="standard-library" tabindex="-1">Standard Library <a class="header-anchor" href="#standard-library" aria-label="Permalink to &quot;Standard Library&quot;">​</a></h2><h3 id="does-vex-have-an-http-client-server" tabindex="-1">Does Vex have an HTTP client/server? <a class="header-anchor" href="#does-vex-have-an-http-client-server" aria-label="Permalink to &quot;Does Vex have an HTTP client/server?&quot;">​</a></h3><p>Yes. <code>std.http</code> provides a full HTTP/1.1 and HTTP/2 server and client with TLS support. The Fiber framework offers Express-like routing. See the <a href="/docs/std/http/">HTTP documentation</a>.</p><h3 id="does-vex-have-a-package-manager" tabindex="-1">Does Vex have a package manager? <a class="header-anchor" href="#does-vex-have-a-package-manager" aria-label="Permalink to &quot;Does Vex have a package manager?&quot;">​</a></h3><p>Yes. <code>vex pm</code> handles dependencies, publishing, and workspaces. It uses a minimum-version resolution strategy similar to Go modules.</p><h3 id="can-i-call-c-libraries-from-vex" tabindex="-1">Can I call C libraries from Vex? <a class="header-anchor" href="#can-i-call-c-libraries-from-vex" aria-label="Permalink to &quot;Can I call C libraries from Vex?&quot;">​</a></h3><p>Yes. Use <code>extern &quot;C&quot;</code> blocks to declare C functions. See the <a href="/docs/guide/ffi">FFI guide</a> and <a href="/docs/guide/ffi-deep-dive">FFI Deep Dive</a>.</p><h3 id="can-vex-be-called-from-c" tabindex="-1">Can Vex be called from C? <a class="header-anchor" href="#can-vex-be-called-from-c" aria-label="Permalink to &quot;Can Vex be called from C?&quot;">​</a></h3><p>Yes. Use <code>#[no_mangle]</code> and <code>extern &quot;C&quot;</code> on Vex functions. The Vex runtime can be embedded in C applications.</p><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><h3 id="symbol-not-found-at-runtime" tabindex="-1">&quot;Symbol not found&quot; at runtime <a class="header-anchor" href="#symbol-not-found-at-runtime" aria-label="Permalink to &quot;&quot;Symbol not found&quot; at runtime&quot;">​</a></h3><p>A linked native symbol couldn&#39;t be resolved. Ensure all required system libraries are installed and accessible. For custom native dependencies, verify the library path is correct in <code>vex.toml</code>.</p><h3 id="borrow-checker-error-that-seems-wrong" tabindex="-1">&quot;Borrow checker&quot; error that seems wrong <a class="header-anchor" href="#borrow-checker-error-that-seems-wrong" aria-label="Permalink to &quot;&quot;Borrow checker&quot; error that seems wrong&quot;">​</a></h3><p>The borrow checker (NLL) is conservative. Try:</p><ol><li>Reducing the scope of mutable borrows</li><li>Copying/cloning values instead of borrowing</li><li>Restructuring code to avoid overlapping borrows</li><li>Using <code>RefCell&lt;T&gt;</code> or <code>Mutex&lt;T&gt;</code> for runtime borrow checking (when compile-time checks are too restrictive)</li></ol><h3 id="compiler-panic-ice-internal-compiler-error" tabindex="-1">Compiler panic / ICE (Internal Compiler Error) <a class="header-anchor" href="#compiler-panic-ice-internal-compiler-error" aria-label="Permalink to &quot;Compiler panic / ICE (Internal Compiler Error)&quot;">​</a></h3><p>This is a bug. Please report it at <a href="https://github.com/meftunca/vex/issues" target="_blank" rel="noreferrer">github.com/meftunca/vex/issues</a> with:</p><ul><li>The Vex source code that triggered it</li><li>Vex version (<code>vex --version</code>)</li><li>Platform (OS and architecture)</li><li>The full error output</li></ul><h3 id="tests-pass-locally-but-fail-in-ci" tabindex="-1">Tests pass locally but fail in CI <a class="header-anchor" href="#tests-pass-locally-but-fail-in-ci" aria-label="Permalink to &quot;Tests pass locally but fail in CI&quot;">​</a></h3><p>Common causes:</p><ul><li>Platform differences (CI runs Linux, you&#39;re on macOS)</li><li>Different Vex version (pin the version in CI)</li><li>Undefined behavior (run with <code>--sanitize=address</code> to detect)</li><li>Race conditions (run with <code>--sanitize=thread</code>)</li></ul><h2 id="getting-help" tabindex="-1">Getting Help <a class="header-anchor" href="#getting-help" aria-label="Permalink to &quot;Getting Help&quot;">​</a></h2><ul><li><strong>Documentation:</strong> This site (<code>/docs/</code>)</li><li><strong>Discord:</strong> <a href="https://discord.gg/vex" target="_blank" rel="noreferrer">Vex Language Server</a></li><li><strong>GitHub Issues:</strong> <a href="https://github.com/meftunca/vex/issues" target="_blank" rel="noreferrer">github.com/meftunca/vex/issues</a></li><li><strong>GitHub Discussions:</strong> <a href="https://github.com/meftunca/vex/discussions" target="_blank" rel="noreferrer">github.com/meftunca/vex/discussions</a></li></ul>',66)])])}const m=a(i,[["render",s]]);export{p as __pageData,m as default};
